import{_ as t,o as n,c as o,a3 as i}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"14. Dispute Resolution Procedure","description":"","frontmatter":{"title":"14. Dispute Resolution Procedure","eba":"Biomedical Engineers 2025-2028","topics":["leave","disputes","preliminary"]},"headers":[],"relativePath":"ebas/biomedical-engineers/consultation-disputes/14-dispute-resolution-procedure.md","filePath":"ebas/biomedical-engineers/consultation-disputes/14-dispute-resolution-procedure.md"}'),s={name:"ebas/biomedical-engineers/consultation-disputes/14-dispute-resolution-procedure.md"};function r(a,e,p,l,h,d){return n(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="_14-dispute-resolution-procedure" tabindex="-1">14. Dispute Resolution Procedure <a class="header-anchor" href="#_14-dispute-resolution-procedure" aria-label="Permalink to &quot;14. Dispute Resolution Procedure&quot;">​</a></h1><p><strong>14.1</strong> Resolution of disputes and grievances</p><p><strong>(a)</strong> For the purpose of this clause 14, a dispute includes a grievance.</p><p><strong>(b)</strong> This dispute resolution procedure will apply to any dispute arising in relation to:</p><p><strong>(i)</strong> this Agreement (for the avoidance of doubt, this includes a request for flexible working arrangements or a request for an additional 12 months&#39; parental leave); or</p><p><strong>(ii)</strong> the NES.</p><p><strong>(c)</strong> A Party for the purposes of this clause is the Employee/s or the Employer that are subject to the dispute.</p><p><strong>(d)</strong> A Party subject to the dispute may choose to be represented at any stage by a representative including a Union or employer organisation. A representative, including a Union or employer organisation on behalf of an Employer, may initiate a dispute.</p><p><strong>14.2</strong> Obligations</p><p><strong>(a)</strong> The Parties to the dispute and their representatives must genuinely attempt to resolve the dispute through the processes set out in this clause and must cooperate to ensure that these processes are carried out expeditiously.</p><p><strong>(b)</strong> While the dispute resolution procedure is being conducted, work will continue normally according to the usual practice that existed before the dispute until the dispute is resolved.</p><p><strong>(c)</strong> This requirement does not apply where an Employee:</p><p><strong>(i)</strong> has a reasonable concern about an imminent risk to their health or safety;</p><p><strong>(ii)</strong> has advised the Employer of the concern; and</p><p><strong>(iii)</strong> has not unreasonably failed to comply with a direction by the Employer to perform other available work that is safe and appropriate for the Employee to perform.</p><p><strong>(d)</strong> No Party to a dispute or person covered by the Agreement will be prejudiced with respect to the resolution of the dispute by continuing work under this clause.</p><p><strong>14.3</strong> Dispute settlement facilitation</p><p><strong>(a)</strong> Where the chosen representative is another Employee of the Employer, that Employee will be released by the Employer from normal duties as is reasonably necessary to enable them to represent the Employee/s including:</p><p><strong>(i)</strong> investigating the circumstances of the dispute; and</p><p><strong>(ii)</strong> participating in the processes to resolve the dispute, including conciliation and arbitration.</p><p><strong>(b)</strong> An Employee who is a Party to the dispute will be released by the Employer from normal duties as is reasonably necessary to enable them to participate in this dispute settling procedure so long as it does not unduly affect the operations of the Employer.</p><p><strong>14.4</strong> Discussion of dispute at workplace</p><p><strong>(a)</strong> The Parties will attempt to resolve the dispute at the workplace as follows:</p><p><strong>(i)</strong> in the first instance by discussions between the Employee/s and the Employee&#39;s line manager or other relevant manager; and</p><p><strong>(ii)</strong> if the dispute is still unresolved, by discussions between the Employee/s and more senior managers.</p><p><strong>(b)</strong> Nothing in this clause 14.4 prevents the Parties from agreeing, at any time, to conducting their discussions in writing, subject to clause 14.2.</p><p><strong>(c)</strong> The discussions at subclause 14.4(a) will take place within fourteen days or such longer period as mutually agreed, save that agreement will not be unreasonably withheld.</p><p><strong>(d)</strong> Where a Party believes the requirements of this clause 14.4 have not been complied with, they will notify the other of their concern in writing as soon as practicable.</p><p><strong>(e)</strong> If a dispute cannot be resolved at the workplace it may be referred by a Party to the dispute or representative to the Commission for conciliation and, if the matter in dispute remains unresolved, arbitration.</p><p><strong>14.5</strong> Disputes of a collective character Disputes of a collective character may be dealt with more expeditiously by an early reference to the Commission. However, no dispute of a collective character may be referred to the Commission directly without a genuine attempt to resolve the dispute at the workplace level.</p><p><strong>14.6</strong> Conciliation</p><p><strong>(a)</strong> Where a dispute is referred for conciliation, the Commission member will do everything the member deems right and proper to assist the Parties to settle the dispute.</p><p><strong>(b)</strong> Conciliation before the Commission is complete when:</p><p><strong>(i)</strong> the Parties to the dispute agree that it is settled; or</p><p><strong>(ii)</strong> the Commission member conducting the conciliation, either on their own motion or after an application by a Party, is satisfied there is no likelihood that further conciliation will result in settlement within a reasonable period; or</p><p><strong>(iii)</strong> the Parties to the dispute inform the Commission member there is no likelihood the dispute will be settled and the member does not have substantial reason to refuse to regard conciliation as complete.</p><p><strong>14.7</strong> Arbitration</p><p><strong>(a)</strong> If, when conciliation is complete, the dispute is not settled, either Party may request the Commission proceed to determine the dispute by arbitration.</p><p><strong>(b)</strong> The Commission member that conciliated the dispute will not arbitrate the dispute if a Party objects to the member doing so.</p><p><strong>(c)</strong> Subject to subclause 14.7(d) below, a decision of the Commission is binding upon the persons covered by this Agreement.</p><p><strong>(d)</strong> An appeal lies to a Full Bench of the Commission, with the leave of the Full Bench, against a determination of a single member of the Commission made pursuant to this clause.</p><p><strong>14.8</strong> Conduct of matters before the Commission</p><p><strong>(a)</strong> Subject to any agreement between the Parties to the dispute in relation to a particular dispute or grievance and the provisions of this clause, in dealing with a dispute or grievance through conciliation or arbitration, the Commission will conduct the matter in accordance with sections 577, 578 and Subdivision B of Division 3 of</p><p><strong>(b)</strong> For the avoidance of doubt, nothing in this clause affects the operation of section 596 of the Act.</p><p>14A Alternative Dispute Resolution Procedure</p><p><strong>14A.1</strong> Application The Alternative Dispute Resolution Panel (Panel) is empowered to hear and determine disputes under this Agreement in relation to the classification of an Employee or the progression between classifications.</p><p><strong>14A.2</strong> Composition and principles of the Panel</p><p><strong>(a)</strong> The Panel for each dispute will comprise three persons being:</p><p><strong>(i)</strong> a nominee of the Union (on behalf of the Employee/s);</p><p><strong>(ii)</strong> a nominee of the VHIA (on behalf of the Employer); and</p><p><strong>(iii)</strong> an independent chairperson (Chair) agreed by the Union and the VHIA or in the absence of agreement, as nominated by the Minister for Health. Note: A nominee of the Union or VHIA may change at any stage depending on the nature of the matter being determined by the Panel.</p><p><strong>(b)</strong> The Panel Chair shall act as an independent third party in deliberations of the Panel.</p><p><strong>(c)</strong> A nominee on the Panel must recuse themselves from being involved in a matter if they are directly and/or personally affected by the outcome.</p><p><strong>(d)</strong> The Panel will commence determining an application made under this clause within 21 days of receiving the application and conclude its deliberations as expeditiously as possible.</p><p><strong>(e)</strong> The Panel shall act independently of the Union, the VHIA and the Victorian Government.</p><p><strong>(f)</strong> The parties to an application to the Panel bear their own costs (save for the Chair).</p><p><strong>(g)</strong> The Panel shall be responsible for determining its own procedure, provided that it applies the rules of natural justice and procedural fairness and be consistent with the requirements of clause 14 (Dispute Resolution Procedure).</p><p><strong>(h)</strong> The Panel shall apply an inquisitorial procedure, rather than an adversarial one.</p><p><strong>(i)</strong> The Panel may decide to hear a matter in the workplace. In such cases the Employer shall provide a suitable meeting room and other relevant facilities for any date agreed with the Panel. The Employer will allow the Panel to inspect any work site if the Panel believes this will assist it in determining a matter, subject to any health, safety, and privacy considerations. A party to a dispute may request that the Panel hear a matter in a workplace. The Panel will consider such a request and determine for itself the best location for hearing a matter.</p><p><strong>(j)</strong> In the exercise of its functions, the Panel shall do such things as are necessary to ensure that:</p><p><strong>(i)</strong> matters are dealt with expeditiously; and</p><p><strong>(ii)</strong> where possible it does not deal with unnecessarily complex legal arguments in hearing/determining a matter.</p><p><strong>(k)</strong> Lawyers and paid agents, who are not direct employees of the Union, VHIA, Department or an Employer may not be given permission to appear before the Panel.</p><p><strong>(l)</strong> A party to a dispute that is being dealt with under this clause shall not make an application to the Commission for it to deal with the same dispute, other than an application made under subclause 14.8(j) – (n). Nothing prevents an application to</p><p>the Commission where the Panel ceases to deal with a dispute without having made a determination (including situations where an applicant has discontinued or withdrawn their matter).</p><p><strong>14A.3</strong> Functions of the Panel Chair The Chair shall perform the following functions:</p><p><strong>(a)</strong> notify all parties to the matter and the Department of the hearing dates;</p><p><strong>(b)</strong> chair proceedings of the Panel;</p><p><strong>(c)</strong> conciliate matters, by chairing conferences between the employer(s) and/or their representative/s, and the Union; and</p><p><strong>(d)</strong> anything else necessary to give effect to the provisions of this clause.</p><p><strong>14A.4</strong> Application to Panel to deal with a dispute</p><p><strong>(a)</strong> Either an Employer or an Employee/s (or their representatives) may make an application to the Panel to determine a dispute only where the Parties have attempted to resolve the dispute at the workplace as described at subclause 14.4 of the Agreement.</p><p><strong>(b)</strong> If the provisions of subclause 14.4 (Discussion of dispute at workplace) or clause</p><p><strong>14.2</strong> (Obligations) have not been complied with prior to the application, the Chair will refer the parties back to the workplace to attempt resolution through discussion at the workplace level in the first instance.</p><p><strong>(c)</strong> Applications to the Panel to deal with a dispute will be in the following or similar form:</p><p>Name of Applicant</p><p>Employer</p><p>Union</p><p>Name of Employee/s involved</p><p>Relevant Enterprise Agreement and Provision</p><p>Description of the dispute and relevant issues</p><p>Current status of matters</p><p>Steps already taken to resolve the dispute</p><p><strong>(d)</strong> Application by an Employee/s</p><p><strong>(i)</strong> An Employee/s may only make an application directly to the Panel where the matter directly involves and affects them.</p><p><strong>(ii)</strong> The Chair shall notify the Union, VHIA and the Employer of an application made by an Employee directly to the Panel.</p><p><strong>(iii)</strong> Before referral to the Panel for determination, the Chair in the first instance shall review the Employee’s application to determine that the nature of the</p><p>dispute is within the scope of this clause and therefore able to be determined by the Panel.</p><p><strong>(iv)</strong> The Chair will notify the Employee, the Union, VHIA and the Employer of their findings with respect to scope.</p><p><strong>(v)</strong> If the Chair finds the Employee’s application is not within the scope of this clause the Chair will notify the Employee that their application is not able to be heard by the Panel.</p><p><strong>(vi)</strong> If the Chair finds the Employee’s application is within the scope of this clause the Chair will notify the Employee that it will be dealt with under this clause.</p><p><strong>14A.5</strong> Roles, procedures, and determinations of the Panel</p><p><strong>(a)</strong> In dealing with an application, the matters the Panel will have regard to include:</p><p><strong>(i)</strong> available relevant material;</p><p><strong>(ii)</strong> the provisions of the Agreement;</p><p><strong>(iii)</strong> materials submitted by the Employee’s and/or Union;</p><p><strong>(iv)</strong> materials submitted by the Employer and/or VHIA;</p><p><strong>(v)</strong> in the case of submissions under subclause 14A.6 below, any materials submitted by or on behalf of the Department.</p><p><strong>(b)</strong> Subject to the provisions of this clause, proceedings of the Panel shall be conducted as informally as possible and undertaken with all possible expediency.</p><p><strong>(c)</strong> The Panel may inform itself in any manner it sees fit including by seeking the views of an expert advisor (who is not an employee of the health service subject of the application) agreed by the Panel to provide clinical expertise in an area of clinical practice relevant to the classification matter under consideration.</p><p><strong>(d)</strong> The Panel is not bound by the rules of evidence and procedure. The Panel will determine the manner in which an Employee/s providing evidence to the Panel will be questioned, save that where possible they will ensure that any questioning is not adversarial in nature.</p><p><strong>(e)</strong> The:</p><p><strong>(i)</strong> Employer and/or VHIA; and</p><p><strong>(ii)</strong> the Employee/s and/or Union; can advocate to the Panel.</p><p><strong>(f)</strong> At the Panel’s discretion, the parties to a matter will present submissions verbally and/or in writing.</p><p><strong>(g)</strong> The parties to a dispute shall have full, unrestricted access to relevant information, except where the Panel determines that access to material is inappropriate for legal or confidentiality reasons.</p><p><strong>(h)</strong> The Panel will determine applications by majority, with written reasons to be prepared by the Chair (including any dissenting determination or a summary of any dissenting determination) and provided to the parties.</p><p><strong>(i)</strong> No determination of the Panel shall be regarded as a precedent.</p><p><strong>(j)</strong> A determination of the Panel will be considered binding unless the:</p><p><strong>(i)</strong> Employee/s and/or Union; and/or</p><p><strong>(ii)</strong> Employer and/or VHIA</p><p>makes an application to have the Commission deal with the matter within 21 days of receiving the written determination and the matter is resolved in accordance with the dispute resolution procedure.</p><p><strong>(k)</strong> An application to the Commission will include the application, determination, written reasons and supporting material.</p><p><strong>(l)</strong> An application to the Commission under this clause will include a request that the President of the Commission will appoint a member of the Commission to preside over the matter.</p><p><strong>(m)</strong> Where applicable, the Commission will be assisted by the Chairperson, who will explain their recommendation, the application and supporting material, and inform the Commission of the position of the Union and the VHIA.</p><p><strong>(n)</strong> Where applicable, the Commission will adopt an inquisitorial procedure (rather than an adversarial procedure) and will in effect stand in the shoes of the Panel and determine whether the Panel decision under review was properly reached and may substitute or uphold the existing determination. Any determination under this clause will be final and binding upon the parties and will not be subject to an appeal of the Full Bench.</p><p><strong>14A.6</strong> Additional Role of the Chair in considering matters affecting an Employer’s funding</p><p><strong>(a)</strong> The Union and the VHIA recognise that the Victorian Government, represented by the Department, has a right to have its funding interests heard and considered in decisions of the Panel.</p><p><strong>(b)</strong> The interests of the Victorian Government represented by the Department include significant funding, policy and service delivery considerations and implications.</p><p><strong>14A.7</strong> Materials to be provided to the Panel</p><p><strong>(a)</strong> A Party shall provide all relevant material to the Panel and the other Party as soon as practicable. Relevant material may include the following:</p><p><strong>(i)</strong> staffing/EFT levels and profiles;</p><p><strong>(ii)</strong> position descriptions;</p><p><strong>(iii)</strong> proposed and/or actual professional reporting lines for/to the proposed position/s; and/or</p><p><strong>(iv)</strong> organisational structure.</p><p><strong>14A.8</strong> Notification of Panel determinations</p><p><strong>(a)</strong> The Chair will notify the Union, Employer and Employee’s (and their representative, where applicable) of the Panel’s determination in writing within 14 days of the decision.</p><p><strong>(b)</strong> The determined Class will apply from the date of the application.</p><p><strong>(c)</strong> Until the determination of the Panel, the existing Class will continue to apply.</p><p><strong>(d)</strong> Where the Panel or, on review the Commission, determines that a lower classification applies, the Employee will have their current salary maintained.</p><p><strong>14A.9</strong> Employee Release from normal duty</p><p><strong>(a)</strong> An Employee/s who is involved in a dispute before the Panel, including a Union representative and/or panel nominee, will be released by the Employer with pay from normal duties as is reasonably necessary to enable them to participate in this dispute settling procedure so long as it does not unduly affect the operations of the Employer.</p><p><strong>(b)</strong> For the purposes of this clause ‘pay’ shall include shift allowances and any other payment the Employee, including a Union representative and/or panel nominee would have received had they not been released from duty as described above.</p><p><strong>14A.10</strong> Withdrawal of application</p><p><strong>(a)</strong> The notifier of a dispute to the Panel may withdraw their application at any time.</p><p><strong>(b)</strong> Any notice of withdrawal of a matter shall be in writing and the Chair shall cause this to be communicated to other relevant parties.</p><p>Plain language terms: dispute, grievance, FWC dispute.</p>',137)])])}const m=t(s,[["render",r]]);export{g as __pageData,m as default};
